import json
from pathlib import Path
from dataclasses import dataclass, asdict
from typing import Iterator

@dataclass
class Product:
    id: int
    name: str
    price: float
    category: str

    @property
    def discounted_price(self) -> float:
        return round(self.price * 0.9, 2)

def load_products(filepath: Path) -> Iterator[Product]:
    data = json.loads(filepath.read_text())
    for item in data["products"]:
        yield Product(
            id=item["id"],
            name=item["name"],
            price=float(item["price"]),
            category=item["category"],
        )

def process(filepath: Path, output: Path, min_price: float = 10.0) -> None:
    products = load_products(filepath)
    eligible = (p for p in products if p.price >= min_price)
    sorted_products = sorted(eligible, key=lambda p: p.price, reverse=True)

    result = [
        {**asdict(p), "discounted_price": p.discounted_price}
        for p in sorted_products
    ]
    output.write_text(json.dumps(result, indent=2))
    print(f"Processed {len(result)} products → {output}")

# Usage:
# process(Path("products.json"), Path("output.json"), min_price=25.0)
